class Solution:
    def closestDivisors(self, num: int):
        import math
        best = None
        best_diff = float('inf')
        for n in [num + 1, num + 2]:
            for a in range(1, int(math.isqrt(n)) + 1):
                if n % a == 0:
                    b = n // a
                    if b - a < best_diff:
                        best_diff = b - a
                        best = [a, b]
        return best

