var closestDivisors = function(num) {
    let best = null, bestDiff = Infinity;
    for (const n of [num + 1, num + 2]) {
        for (let a = 1; a * a <= n; a++) {
            if (n % a === 0) {
                const b = n / a;
                if (b - a < bestDiff) { bestDiff = b - a; best = [a, b]; }
            }
        }
    }
    return best;
};
